mapper.insert:
INSERT INTO OUTBOUNDS (
    OUTBOUND_NO, OUTBOUND_TYPE, CUSTOMER_ID, WAREHOUSE_ID, OUTBOUND_DATE, CREATED_USER_ID, REMARK
) VALUES (
    #{outboundNo}, #{outboundType}, #{customerId}, #{warehouseId}, #{outboundDate}, #{createdUserId}, #{remark}
)

INSERT INTO OUTBOUND_DETAILS (
    OUTBOUND_ID, ITEM_ID, QUANTITY, UNIT_PRICE, TOTAL_PRICE, REMARK
) VALUES (
    #{outboundId}, #{itemId}, IFNULL(#{quantity}, 0),
    IFNULL(#{unitPrice}, 0.00), IFNULL(#{totalPrice}, 0.00), #{remark}
)
